//General Statistics
let startDate = datetime(2026-03-18);
let endDate = datetime(2026-03-20);
let allSessionsStats = allSessions(startDate,endDate)
| summarize Value=count(), Fabric = countif(pool=="Fabric"), SQL = countif(pool=="SQL") by bin(localtime,1d)
| project Date=localtime, Category = "Total Sessions", Value, Fabric, SQL;
let uniqueSessionsStats = allSessions(startDate,endDate)
| summarize Value = count_distinct(userId), Fabric = countif(pool=="Fabric"), SQL = countif(pool=="SQL") by bin(localtime,1d)
| project Date= localtime, Category = "Total Unique Players", Value, Fabric, SQL;
let questionsAnswered = allSessions(startDate,endDate)
| summarize Value = sum(questionsAnswered), Fabric = sumif(questionsAnswered,pool=="Fabric"), SQL = sumif(questionsAnswered,pool=="SQL") by bin(localtime,1d)
| project Date= localtime, Category = "Total Questions Answered", Value, Fabric, SQL;
let correctQuestions = allSessions(startDate,endDate)
| summarize Value = sum(correctAnswers), Fabric = sumif(correctAnswers,pool=="Fabric"), SQL = sumif(correctAnswers,pool=="SQL")  by bin(localtime,1d)
| project Date= localtime, Category = "Total Correct Questions Answered", Value, Fabric, SQL;
let incorrectQuestions = allSessions(startDate,endDate)
| summarize Value = sum(questionsAnswered - correctAnswers), Fabric = sumif(questionsAnswered - correctAnswers,pool=="Fabric"), SQL = sumif(questionsAnswered - correctAnswers,pool=="SQL")  by bin(localtime,1d)
| project Date= localtime, Category = "Total Incorrect Questions Answered", Value, Fabric, SQL;
let totalLocations = allSessions(startDate,endDate)
| summarize Value = count_distinct(iff(isempty( state),country,state)), Fabric = count_distinctif(iff(isempty( state),country,state),pool=="Fabric"), SQL=count_distinctif(iff(isempty( state),country,state),pool=="SQL") by bin(localtime,1d)
| project Date= localtime, Category = "Total Locations", Value, Fabric, SQL;
allSessionsStats
| union uniqueSessionsStats, questionsAnswered, correctQuestions,incorrectQuestions, totalLocations
| extend Date = format_datetime(Date,"yyyy-MM-dd")
| order by Category, Date asc 
| extend Total=row_cumsum(Value, Category != prev(Category)),TotalFabric=row_cumsum(Fabric, Category != prev(Category)),TotalSQL=row_cumsum(SQL, Category != prev(Category))

//Top 5 by location (State and country)
let startDate = datetime(2026-03-18);
let endDate = datetime(2026-03-20);
let topLocations = allSessions(startDate,endDate)
| extend Location = iff(isempty(state),country,state), Track = pool
| summarize Value = count() by Location, bin(localtime,1d)
| partition by localtime (top 5 by Value)
| order by localtime asc 
| extend DateStr = format_datetime(localtime,"yyyy-MM-dd")
| project Date= DateStr, Category = "Top Locations", Location, Value;
topLocations

//Top 5 by location (State and ccountry) and track
let startDate = datetime(2026-03-18);
let endDate = datetime(2026-03-20);
let topLocations = allSessions(startDate,endDate)
| extend Location = iff(isempty(state),country,state), Track = pool
| summarize Value = count() by Location, bin(localtime,1d), Track
| partition by localtime (top 5 by Value)
| order by localtime asc 
| project Date= localtime, Category = "Top Locations", Location, Value, Track;
topLocations


//Top 5 by location (Country)
let startDate = datetime(2026-03-18);
let endDate = datetime(2026-03-20);
let topLocations = allSessions(startDate,endDate)
| extend Location = country, Track = pool
| summarize Value = count() by Location, bin(localtime,1d)
| partition by localtime (top 5 by Value)
| order by localtime asc 
| project Date= localtime, Category = "Top Locations", Location, Value;
topLocations

//Top 5 by location (Country and Track)
let startDate = datetime(2026-03-18);
let endDate = datetime(2026-03-20);
let topLocations = allSessions(startDate,endDate)
| extend Location = country, Track = pool
| summarize Value = count() by Location, bin(localtime,1d), Track
| partition by localtime (top 5 by Value)
| order by localtime asc 
| project Date= localtime, Category = "Top Locations", Location, Value, Track;
topLocations


let startDate = datetime(2026-03-18);
let endDate = datetime(2026-03-20);
allSessions(startDate,endDate)
| where questionsAnswered > 0 
| project localtime, sessionId, userId, questionsAnswered, gameTime, rateAnswered = gameTime/questionsAnswered, FinalScore
| top 10 by rateAnswered asc 
| project Date = format_datetime(localtime,"yyyy-MM-dd"), QuestionsAnswered = questionsAnswered, GameTime=gameTime, RateAnswered = rateAnswered, FinalScore, QuestionPerSecond = questionsAnswered/(gameTime/1s)
